#include <iostream>
#include <stdexcept>

struct RAII {
    RAII()  { std::cout << "생성" << std::endl; }
    ~RAII() { std::cout << "소멸" << std::endl; }
};

void func() {
    RAII r;
    throw std::runtime_error("예외 발생");
}

int main() {
    try {
        func();
    } catch (std::runtime_error& e) {
        std::cout << e.what() << std::endl;
    }
    return 0;
}

#include <iostream>
#include <stdexcept>

int main() {
    try {
        try {
            throw std::runtime_error("내부");
        } catch (std::runtime_error& e) {
            std::cout << "내부 catch: " << e.what() << std::endl;
            throw;
        }
    } catch (std::exception& e) {
        std::cout << "외부 catch: " << e.what() << std::endl;
    }
    return 0;
}

#include <iostream>

int main() {
    try {
        throw 42;
    } catch (double d) {
        std::cout << "double: " << d << std::endl;
    } catch (int i) {
        std::cout << "int: " << i << std::endl;
    } catch (...) {
        std::cout << "unknown" << std::endl;
    }
    return 0;
}

#include <iostream>
#include <new>

int main() {
    try {
        int* p = new int[1000000000000LL];
        delete[] p;
    } catch (std::bad_alloc& e) {
        std::cout << "메모리 할당 실패: " << e.what() << std::endl;
    }
    return 0;
}

