#include <iostream>

class Box {
    int val;
public:
    Box(int v) : val(v) {}
    int getVal() const { return val; }
    void setVal(int v) { val = v; }
};

int main() {
    const Box b(10);
    std::cout << b.getVal() << std::endl;
    // b.setVal(20);  // 이 줄은 주석 처리됨
    return 0;
}

#include <iostream>

class Shared {
public:
    static int count;
    Shared()  { ++count; }
    ~Shared() { --count; }
    static int getCount() { return count; }
};
int Shared::count = 0;

int main() {
    Shared a;
    std::cout << Shared::getCount() << std::endl;
    {
        Shared b, c;
        std::cout << Shared::getCount() << std::endl;
    }
    std::cout << Shared::getCount() << std::endl;
    return 0;
}

